/// <summary>FNV hash of the last GametypeStatusBlock sent to this client (0 = never) — the per-mode
/// round/objective HUD stats (T53) are personalized (KH self-slot, SURV hunter visibility), so each peer
/// gates on the hash of ITS OWN serialized block, resending only when the bytes change.</summary>
public uint LastModeStatusHash;

// Gametype status (T53): per-mode round/objective HUD stats — QC STAT(REDALIVE..PINKALIVE) (CA/FT),
// STAT(OBJECTIVE_STATUS) (KH key pack), eliminatedPlayers (scoreboard grey-out) and survivalStatuses
// (role + hunter disclosure). The block is PERSONALIZED per recipient (KH '31 = self' slot, SURV hunter
// visibility), so serialize per peer into a scratch and hash-gate (steady-state cost = one bool; QC's
// equivalent is stat delta-compression + linked-entity SendFlags).
_modeStatusScratch.Reset();
bool haveModeStatus = XonoticGodot.Net.GametypeStatusBlock.Capture(
    _modeStatusScratch, _world.GameType, owner, _world.Clients.Players, NetIdFor,
    roundStarted: _world.Rounds is { IsRoundStarted: true });
uint modeStatusHash = haveModeStatus ? XonoticGodot.Net.GametypeStatusBlock.Hash(_modeStatusScratch.WrittenSpan) : 0u;
bool sendModeStatus = haveModeStatus && st.LastModeStatusHash != modeStatusHash;
_snapshotWriter.WriteBool(sendModeStatus);
if (sendModeStatus)
{
    _snapshotWriter.WriteBytes(_modeStatusScratch.WrittenSpan);
    st.LastModeStatusHash = modeStatusHash;
}

/// <summary>The latest per-mode round/objective HUD status (T53): CA/FT alive counts + eliminated ids,
/// the KH OBJECTIVE_STATUS key pack, the Survival role + hunter ids. Null until a tracked mode sends one.
/// Consumers: NetGame.UpdateModIcons (ModIconsPanel) + UpdateScoreboard (eliminated grey-out).</summary>
public XonoticGodot.Net.GametypeStatusBlock.Decoded? LatestModeStatus { get; private set; }

// Gametype status (T53): read in lockstep with ServerNet's write order (owner -> movevars -> scoreinfo ->
// scoreboard -> THIS -> entity section). Always consume the bytes to keep the stream aligned.
if (r.ReadBool())
{
    XonoticGodot.Net.GametypeStatusBlock.Decoded? ms = XonoticGodot.Net.GametypeStatusBlock.Deserialize(ref r);
    if (ms is not null && !r.BadRead)
        LatestModeStatus = ms;
}

/// v7: the snapshot gained the bool-gated <see cref="XonoticGodot.Net.GametypeStatusBlock"/> (T53) between the
/// scoreboard block and the entity section — the per-mode round/objective HUD stats (QC STAT(REDALIVE..PINKALIVE),
/// STAT(OBJECTIVE_STATUS) for KeyHunt, the eliminatedPlayers scoreboard grey-out set, and the Survival
/// role/hunter disclosure), personalized per recipient and hash-gated per peer.
/// </summary>
public const uint ProtocolVersion = 7;

/// <summary>Feed + toggle the mod-icons panel (QC HUD_ModIcons_SetFunc -> gametype.m_modicons) from the
/// networked per-mode status (T53). Cheap: property writes + a Visible toggle; the panel repaints itself.</summary>
private void UpdateModIcons()
{
    if (_fullHud is null || _client is null) return;
    var panel = _fullHud.ModIcons;
    XonoticGodot.Net.GametypeStatusBlock.Decoded? ms = _client.LatestModeStatus;
    if (ms is null) { if (panel.Visible) panel.Visible = false; return; }
    switch (ms.Mode)
    {
        case XonoticGodot.Net.GametypeStatusBlock.Kind.ClanArena:
            panel.Mode = Hud.ModIconsPanel.ModIconsMode.ClanArena;
            panel.SetAliveCounts(ms.Alive[0], ms.Alive[1], ms.Alive[2], ms.Alive[3]);
            break;
        case XonoticGodot.Net.GametypeStatusBlock.Kind.FreezeTag:
            panel.Mode = Hud.ModIconsPanel.ModIconsMode.FreezeTag;
            panel.SetAliveCounts(ms.Alive[0], ms.Alive[1], ms.Alive[2], ms.Alive[3]);
            break;
        case XonoticGodot.Net.GametypeStatusBlock.Kind.KeyHunt:
            panel.Mode = Hud.ModIconsPanel.ModIconsMode.Keyhunt;
            panel.ObjectiveStatus = unchecked((int)ms.KeyState);
            break;
        case XonoticGodot.Net.GametypeStatusBlock.Kind.Survival:
            panel.Mode = Hud.ModIconsPanel.ModIconsMode.Survival;
            panel.SurvivalStatus = ms.MyStatus;
            break;
        default:
            panel.Mode = Hud.ModIconsPanel.ModIconsMode.None;
            break;
    }
    panel.MyTeam = ms.MyTeamIndex;
    panel.TeamCount = ms.TeamCount > 0 ? ms.TeamCount : panel.TeamCount;
    bool show = panel.Mode != Hud.ModIconsPanel.ModIconsMode.None;
    if (panel.Visible != show) panel.Visible = show;
}

// inside UpdateScoreboard(), replace the feed condition + SetWireRows call:
